#include <bits/stdc++.h>
using namespace std;
typedef long long ll;

const int N=1e5+10;
const ll INF=1e18;

struct Vec{
    ll a[3];
}t[N<<2];

struct Mtx{
    ll a[3][3];
}tag[N<<2],E,P,C;

Vec operator*(Vec &x,Mtx &y){
    Vec res;
    for(int i=0;i<3;i++){
        res.a[i]=-INF;
        for(int j=0;j<3;j++)
            res.a[i]=max(res.a[i],x.a[j]+y.a[j][i]);
    }
    return res;
}

Vec operator+(Vec x,Vec y){
    Vec res;
    res.a[0]=max(x.a[0],y.a[0]);
    res.a[1]=max(x.a[1],y.a[1]);
    res.a[2]=0;
    return res;
}

Mtx operator*(Mtx &x,Mtx &y){
    Mtx res;
    for(int i=0;i<3;i++)
        for(int j=0;j<3;j++){
            res.a[i][j]=-INF;
            for(int k=0;k<3;k++)
                res.a[i][j]=max(res.a[i][j],x.a[i][k]+y.a[k][j]);
        }
    return res;
}

void Cpy(Mtx &x,Mtx &y){
    for(int i=0;i<3;i++)
        for(int j=0;j<3;j++)
            x.a[i][j]=y.a[i][j];
}

int n,m;
ll a[N];

void build(int cur,int l,int r){
    Cpy(tag[cur],E);
    if(l==r){
        t[cur].a[0]=t[cur].a[1]=a[l];
        t[cur].a[2]=0;
        return;
    }
    int mid=l+r>>1;
    build(cur*2,l,mid);
    build(cur*2+1,mid+1,r);
    t[cur]=t[cur*2]+t[cur*2+1];
}

void Pushdown(int cur){
    t[cur*2]=t[cur*2]*tag[cur];
    tag[cur*2]=tag[cur*2]*tag[cur];
    t[cur*2+1]=t[cur*2+1]*tag[cur];
    tag[cur*2+1]=tag[cur*2+1]*tag[cur];
    Cpy(tag[cur],E);
}

void modify(int cur,int l,int r,int x,int y,Mtx &P){
    if(x<=l && r<=y){
        t[cur]=t[cur]*P;
        tag[cur]=tag[cur]*P;
        return;
    }
    Pushdown(cur);
    int mid=l+r>>1;
    if(x<=mid)
        modify(cur*2,l,mid,x,y,P);
    if(y>mid)
        modify(cur*2+1,mid+1,r,x,y,P);
    t[cur]=t[cur*2]+t[cur*2+1];
}

Vec query(int cur,int l,int r,int x,int y){
    if(x<=l && r<=y)
        return t[cur];
    Pushdown(cur);
    int mid=l+r>>1;
    if(y<=mid)
        return query(cur*2,l,mid,x,y);
    if(x>mid)
        return query(cur*2+1,mid+1,r,x,y);
    return query(cur*2,l,mid,x,y)+query(cur*2+1,mid+1,r,x,y);
}

int main(){
	E.a[0][1]=E.a[0][2]=E.a[1][0]=E.a[1][2]=E.a[2][0]=E.a[2][1]=-INF; 
    P.a[0][1]=P.a[0][2]=P.a[1][2]=P.a[2][0]=P.a[2][1]=-INF;
    C.a[0][1]=C.a[0][2]=C.a[1][0]=C.a[1][1]=C.a[1][2]=-INF;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%lld",&a[i]);
    build(1,1,n);
    scanf("%d",&m);
    while(m--){
        char op[2];
        int x,y,z;
        scanf("%s",op);
        scanf("%d%d",&x,&y);
        if(op[0]=='Q')
            printf("%lld\n",query(1,1,n,x,y).a[1]);
        else if(op[0]=='A')
            printf("%lld\n",query(1,1,n,x,y).a[0]);
        else if(op[0]=='P'){
            scanf("%d",&z);
            P.a[1][0]=P.a[1][1]=z;
            modify(1,1,n,x,y,P);
        }else{
            scanf("%d",&z);
            C.a[2][0]=C.a[2][1]=z;
            modify(1,1,n,x,y,C);
        }
    }
    return 0;
}
